// ── file-upload-basic ─────────────────────────────
interface UploadEntry {
  id: string;
  name: string;
  size: number;
  progress: number;
  failed: boolean;
}

function EvalFileUploadBasic() {
  const [entries, setEntries] = useState<UploadEntry[]>([]);
  const timers = useRef<Map<string, ReturnType<typeof setInterval>>>(new Map());

  useEffect(() => {
    return () => timers.current.forEach(clearInterval);
  }, []);

  function startSimulatedUpload(id: string) {
    const timer = setInterval(() => {
      setEntries((prev) => {
        const next = prev.map((e) =>
          e.id === id && e.progress < 100
            ? { ...e, progress: Math.min(e.progress + 10, 100) }
            : e,
        );
        if (next.find((e) => e.id === id)?.progress === 100) {
          clearInterval(timer);
          timers.current.delete(id);
        }
        return next;
      });
    }, 200);
    timers.current.set(id, timer);
  }

  function handleDropFiles(fileList: FileList) {
    Array.from(fileList).forEach((file) => {
      const id = `${Date.now()}-${Math.random()}`;
      setEntries((prev) => [
        ...prev,
        { id, name: file.name, size: file.size, progress: 0, failed: false },
      ]);
      startSimulatedUpload(id);
    });
  }

  function handleDelete(id: string) {
    const timer = timers.current.get(id);
    if (timer) {
      clearInterval(timer);
      timers.current.delete(id);
    }
    setEntries((prev) => prev.filter((e) => e.id !== id));
  }

  function handleRetry(id: string) {
    setEntries((prev) =>
      prev.map((e) => (e.id === id ? { ...e, progress: 0, failed: false } : e)),
    );
    startSimulatedUpload(id);
  }

  return (
    <FileUpload.Root>
      <FileUpload.DropZone
        hint="PNG, JPG or PDF (max 5 MB)"
        accept="image/*,application/pdf"
        maxSize={5 * 1024 * 1024}
        allowsMultiple
        onDropFiles={handleDropFiles}
      />
      <FileUpload.List>
        {entries.map((entry) => (
          <FileUpload.ListItemProgressBar
            key={entry.id}
            name={entry.name}
            size={entry.size}
            progress={entry.progress}
            failed={entry.failed}
            onDelete={() => handleDelete(entry.id)}
            onRetry={() => handleRetry(entry.id)}
          />
        ))}
      </FileUpload.List>
    </FileUpload.Root>
  );
}

