function EvalImageCropperBasiccenterAspectCrop(mediaWidth: number, mediaHeight: number, aspect: number) {
  return centerCrop(
    makeAspectCrop({ unit: '%', width: 80 }, aspect, mediaWidth, mediaHeight),
    mediaWidth,
    mediaHeight,
  );
}

function EvalImageCropperBasic() {
  const [imageSrc, setImageSrc] = React.useState<string>();
  const [crop, setCrop] = React.useState<Crop>();
  const [completedCrop, setCompletedCrop] = React.useState<PixelCrop>();
  const [previewUrl, setPreviewUrl] = React.useState<string>();

  function handleFileSelect(files: FileList | null) {
    if (!files || files.length === 0) return;
    const reader = new FileReader();
    reader.onload = (e) => {
      setImageSrc(e.target?.result as string);
      setCrop(undefined);
      setCompletedCrop(undefined);
      setPreviewUrl(undefined);
    };
    reader.readAsDataURL(files[0]);
  }

  function handleImageLoad(event: React.SyntheticEvent<HTMLImageElement>) {
    const { naturalWidth: width, naturalHeight: height } = event.currentTarget;
    setCrop(EvalImageCropperBasiccenterAspectCrop(width, height, 1));
  }

  async function handleSave() {
    if (!completedCrop || !imageSrc) return;
    const file = await cropToFile(imageSrc, completedCrop);
    if (file) {
      setPreviewUrl(URL.createObjectURL(file));
    }
  }

  function handleCancel() {
    setImageSrc(undefined);
    setCrop(undefined);
    setCompletedCrop(undefined);
    setPreviewUrl(undefined);
  }

  return (
    <Column gap="l" style={{ maxWidth: 480 }}>
      <Column gap="xs">
        <Text variant="heading" as="h2" size="m">Upload avatar photo</Text>
        <Text color="muted" size="s">
          Select a photo and crop it to a square for your profile.
        </Text>
      </Column>

      {!imageSrc ? (
        <FileTrigger onSelect={handleFileSelect} acceptedFileTypes={['image/*']}>
          <Button variant="neutral" size="lg">Choose photo</Button>
        </FileTrigger>
      ) : (
        <Column gap="m">
          <ImageCropper.Root
            crop={crop}
            onChange={setCrop}
            onComplete={setCompletedCrop}
            aspect={1}
            circularCrop
          >
            <ImageCropper.Img
              src={imageSrc}
              alt="User avatar to crop"
              onLoad={handleImageLoad}
              style={{ maxHeight: 400, width: '100%' }}
            />
          </ImageCropper.Root>

          {previewUrl && (
            <Row gap="s" style={{ alignItems: 'center' }}>
              <Text size="s" color="muted">Preview:</Text>
              <Avatar.Root size="lg">
                <Avatar.Image src={previewUrl} alt="Cropped avatar preview" />
              </Avatar.Root>
            </Row>
          )}

          <Row gap="s" style={{ justifyContent: 'flex-end' }}>
            <Button variant="neutral" size="lg" onPress={handleCancel}>
              Cancel
            </Button>
            <Button variant="primary" size="lg" onPress={handleSave}>
              Save avatar
            </Button>
          </Row>
        </Column>
      )}
    </Column>
  );
}

